import { createOverviewControllerBundle } from '../modules/overview/controllerBundle.js';

export function createAppOverviewControllerBundle(deps = {}) {
  const {
    appState,
    calculateQuantScore,
    elements: els,
    emptyBlock,
    formatScore,
    getCountryLabel,
    getDefaultRegion,
    getInitials,
    getLanguage,
    getLocale,
    getQuantScore,
    getRank,
    getRegionLabel,
    getSkillScore,
    getStreak,
    getWeeklyXp,
    hashStringToHue,
    leaderboardCloudController,
    loadStateForUser,
    normalizeAccount,
    normalizeCountry,
    normalizeLeaderboardSettings,
    normalizeRegionForCountry,
    normalizeSkills,
    refreshIcons,
    refreshLeaderboardFromCloud,
    renderCountryOptions,
    renderRegionOptions,
    saveState,
    skillDefs,
    t,
    updateCheckInPill,
    updateUnreadMessageBadge,
    userState
  } = deps;

  return createOverviewControllerBundle({
    elements: els,
    getRawSettings: () => userState.value.leaderboard,
    setRawSettings: (settings) => {
      userState.value.leaderboard = settings;
    },
    normalizeLeaderboardSettings,
    getCurrentUser: () => appState.currentUser,
    getAccounts: () => appState.auth.accounts,
    loadStateForUser,
    getCloudRows: () => leaderboardCloudController.getRows(),
    getCloudSnapshot: () => leaderboardCloudController.getSnapshot(),
    refreshCloud: refreshLeaderboardFromCloud,
    normalizeAccount,
    normalizeSkills,
    calculateQuantScore,
    getSkillScore,
    getCountryLabel,
    getRegionLabel,
    getRank,
    getDefaultRegion,
    normalizeCountry,
    normalizeRegionForCountry,
    skillDefs,
    t,
    getLanguage,
    renderCountryOptions,
    renderRegionOptions,
    hashStringToHue,
    getInitials,
    formatScore,
    emptyBlock,
    refreshIcons,
    saveState,
    getQuantScore,
    getStreak,
    getEntryCount: () => userState.value.entries.length,
    getWeeklyXp,
    getLocale,
    updateUnreadMessageBadge,
    updateCheckInPill,
    now: () => new Date()
  });
}
